-- /app/scripts/seed-concern-areas.sql
-- Auto-generated from /app/frontend/server/src/scripts/seed-concerns.ts
-- 160 concern areas across all categories
-- Idempotent: safe to re-run

CREATE TABLE IF NOT EXISTS concern_areas (
  id              SERIAL PRIMARY KEY,
  category        TEXT NOT NULL,
  concern_area    TEXT NOT NULL,
  parent_worry    TEXT NOT NULL,
  impact_on_child TEXT NOT NULL,
  assessment_type TEXT,
  search_keywords TEXT,
  services        JSONB NOT NULL DEFAULT '[]'::jsonb,
  roles           JSONB NOT NULL DEFAULT '[]'::jsonb,
  is_active       BOOLEAN NOT NULL DEFAULT TRUE,
  sort_order      INTEGER NOT NULL DEFAULT 0,
  created_at      TIMESTAMP NOT NULL DEFAULT now(),
  updated_at      TIMESTAMP NOT NULL DEFAULT now(),
  UNIQUE (category, concern_area)
);
CREATE INDEX IF NOT EXISTS idx_concern_areas_category ON concern_areas(category);
CREATE INDEX IF NOT EXISTS idx_concern_areas_active ON concern_areas(is_active);

ON CONFLICT (category, concern_area) DO UPDATE SET
  parent_worry = EXCLUDED.parent_worry,
  impact_on_child = EXCLUDED.impact_on_child,
  assessment_type = EXCLUDED.assessment_type,
  search_keywords = EXCLUDED.search_keywords,
  sort_order = EXCLUDED.sort_order,
  updated_at = now();
